import{_ as l,o as e,c as a,a as t}from"./app.ffa5e1d0.js";const _=JSON.parse('{"title":"RAGFlow 全流程部署与知识库实战指南","description":"","frontmatter":{},"headers":[{"level":2,"title":"一、 核心业务逻辑流程图 (RAG 核心原理)","slug":"一、-核心业务逻辑流程图-rag-核心原理","link":"#一、-核心业务逻辑流程图-rag-核心原理","children":[]},{"level":2,"title":"二、 环境准备 (Pre-requisites)","slug":"二、-环境准备-pre-requisites","link":"#二、-环境准备-pre-requisites","children":[{"level":3,"title":"1. 硬件要求（硬性指标）","slug":"_1-硬件要求-硬性指标","link":"#_1-硬件要求-硬性指标","children":[]},{"level":3,"title":"2. 软件依赖","slug":"_2-软件依赖","link":"#_2-软件依赖","children":[]}]},{"level":2,"title":"三、 本地搭建步骤 (Installation)","slug":"三、-本地搭建步骤-installation","link":"#三、-本地搭建步骤-installation","children":[{"level":3,"title":"1. 克隆仓库与配置","slug":"_1-克隆仓库与配置","link":"#_1-克隆仓库与配置","children":[]},{"level":3,"title":"2. 启动服务","slug":"_2-启动服务","link":"#_2-启动服务","children":[]},{"level":3,"title":"3. 检查运行状态","slug":"_3-检查运行状态","link":"#_3-检查运行状态","children":[]},{"level":3,"title":"4. 启动后没多久接口502问题","slug":"_4-启动后没多久接口502问题","link":"#_4-启动后没多久接口502问题","children":[]}]},{"level":2,"title":"四、 知识库配置全流程 (Setup)","slug":"四、-知识库配置全流程-setup","link":"#四、-知识库配置全流程-setup","children":[{"level":3,"title":"1. 登录管理后台","slug":"_1-登录管理后台","link":"#_1-登录管理后台","children":[]},{"level":3,"title":"2. 接入 AI 模型 (最关键一步)","slug":"_2-接入-ai-模型-最关键一步","link":"#_2-接入-ai-模型-最关键一步","children":[]},{"level":3,"title":"3. 构建私有知识库","slug":"_3-构建私有知识库","link":"#_3-构建私有知识库","children":[]}]},{"level":2,"title":"五、 实现 AI 对话 (Chat)","slug":"五、-实现-ai-对话-chat","link":"#五、-实现-ai-对话-chat","children":[]},{"level":2,"title":"六、 踩坑避雷针 (Troubleshooting) ⚡","slug":"六、-踩坑避雷针-troubleshooting-⚡","link":"#六、-踩坑避雷针-troubleshooting-⚡","children":[]},{"level":2,"title":"七、 维护建议","slug":"七、-维护建议","link":"#七、-维护建议","children":[]}],"relativePath":"ai/ais/rag.md","lastUpdated":null}'),s={name:"ai/ais/rag.md"},i=t(`<h1 id="ragflow-全流程部署与知识库实战指南" tabindex="-1">RAGFlow 全流程部署与知识库实战指南 <a class="header-anchor" href="#ragflow-全流程部署与知识库实战指南" aria-hidden="true">#</a></h1><p>本指南旨在帮助开发者在本地快速搭建基于深度文档理解的 RAGFlow 系统。</p><hr><h2 id="一、-核心业务逻辑流程图-rag-核心原理" tabindex="-1">一、 核心业务逻辑流程图 (RAG 核心原理) <a class="header-anchor" href="#一、-核心业务逻辑流程图-rag-核心原理" aria-hidden="true">#</a></h2><p><img src="https://img520.com/8pq1ss.png" alt="RAG流程图"></p><h2 id="二、-环境准备-pre-requisites" tabindex="-1">二、 环境准备 (Pre-requisites) <a class="header-anchor" href="#二、-环境准备-pre-requisites" aria-hidden="true">#</a></h2><h3 id="_1-硬件要求-硬性指标" tabindex="-1">1. 硬件要求（硬性指标） <a class="header-anchor" href="#_1-硬件要求-硬性指标" aria-hidden="true">#</a></h3><ul><li><strong>内存 (RAM)</strong>: <strong>16GB+</strong> (核心组件如 Elasticsearch、MinIO 非常吃内存)。</li><li><strong>CPU</strong>: 4 核以上。</li><li><strong>磁盘</strong>: 50GB 以上可用空间。</li></ul><h3 id="_2-软件依赖" tabindex="-1">2. 软件依赖 <a class="header-anchor" href="#_2-软件依赖" aria-hidden="true">#</a></h3><ul><li><strong>Docker</strong>: 24.0.0+</li><li><strong>Docker Compose</strong>: 2.26.1+</li><li><strong>操作系统</strong>: Windows (WSL2), Linux, 或 macOS。</li></ul><hr><h2 id="三、-本地搭建步骤-installation" tabindex="-1">三、 本地搭建步骤 (Installation) <a class="header-anchor" href="#三、-本地搭建步骤-installation" aria-hidden="true">#</a></h2><h3 id="_1-克隆仓库与配置" tabindex="-1">1. 克隆仓库与配置 <a class="header-anchor" href="#_1-克隆仓库与配置" aria-hidden="true">#</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 克隆项目</span></span>
<span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">clone</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">https://github.com/infiniflow/ragflow.git</span></span>
<span class="line"><span style="color:#82AAFF;">cd</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">ragflow</span></span>
<span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">checkout</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">v0.</span><span style="color:#F78C6C;">24.0</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># (可选) 如果需要修改端口，请编辑 docker-compose.yml</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 将 - 80:80 改为 - 8080:80 以避免端口冲突</span></span>
<span class="line"></span></code></pre></div><h3 id="_2-启动服务" tabindex="-1">2. 启动服务 <a class="header-anchor" href="#_2-启动服务" aria-hidden="true">#</a></h3><p>由于镜像较多（约 10GB+），请耐心等待下载完成。</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 后台启动所有容器</span></span>
<span class="line"><span style="color:#FFCB6B;">docker</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">compose</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">up</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-d</span></span>
<span class="line"></span></code></pre></div><h3 id="_3-检查运行状态" tabindex="-1">3. 检查运行状态 <a class="header-anchor" href="#_3-检查运行状态" aria-hidden="true">#</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 查看所有容器是否为 Up (healthy)</span></span>
<span class="line"><span style="color:#FFCB6B;">docker</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">ps</span></span>
<span class="line"></span></code></pre></div><h3 id="_4-启动后没多久接口502问题" tabindex="-1">4. 启动后没多久接口502问题 <a class="header-anchor" href="#_4-启动后没多久接口502问题" aria-hidden="true">#</a></h3><blockquote><p>注意: 大概率为桌面版的dokcer desktop中资源节省导致的</p><p><img src="https://img520.com/rekJVK.png" alt="解决方案"></p></blockquote><p>提示：如果看到某些容器在重启，通常是因为内存分配不足导致的。</p><h2 id="四、-知识库配置全流程-setup" tabindex="-1">四、 知识库配置全流程 (Setup) <a class="header-anchor" href="#四、-知识库配置全流程-setup" aria-hidden="true">#</a></h2><h3 id="_1-登录管理后台" tabindex="-1">1. 登录管理后台 <a class="header-anchor" href="#_1-登录管理后台" aria-hidden="true">#</a></h3><ul><li>访问地址: 浏览器打开 <a href="http://localhost" target="_blank" rel="noreferrer">http://localhost</a> (默认 80 端口)。</li><li>初始操作: 注册一个新账号并登录。</li></ul><h3 id="_2-接入-ai-模型-最关键一步" tabindex="-1">2. 接入 AI 模型 (最关键一步) <a class="header-anchor" href="#_2-接入-ai-模型-最关键一步" aria-hidden="true">#</a></h3><p>RAGFlow 本身不产出内容，需要接入 LLM（大脑）和 Embedding（翻译官）：</p><ul><li><ol><li>进入右上角 &quot;User Setting&quot; -&gt; &quot;Model Providers&quot;。</li></ol></li><li><ol start="2"><li>接入模型:</li></ol></li></ul><p>在线 API: 填入 DeepSeek 或 OpenAI 的 API Key。</p><p>本地 Ollama: 地址填写 <a href="http://host.docker.internal:11434" target="_blank" rel="noreferrer">http://host.docker.internal:11434</a>。</p><p>设置默认模型: 在 &quot;System Model Config&quot; 中，务必选定一个 Embedding Model，否则无法对文档进行向量化。</p><ul><li><ol start="3"><li>设置默认模型: 在 &quot;System Model Config&quot; 中，务必选定一个 Embedding Model，否则无法对文档进行向量化。</li></ol></li></ul><p><img src="https://img520.com/yI3sAB.jpg" alt="1774685602673.jpg"></p><h3 id="_3-构建私有知识库" tabindex="-1">3. 构建私有知识库 <a class="header-anchor" href="#_3-构建私有知识库" aria-hidden="true">#</a></h3><ul><li><ol><li>点击导航栏 &quot;Knowledge Base&quot; -&gt; &quot;Create Knowledge Base&quot;。</li></ol></li><li><ol start="2"><li>上传文件: 支持 PDF, Word, Excel, Markdown。</li></ol></li><li><ol start="3"><li>解析策略 (Chunk Method):</li></ol><ul><li>General: 适用于常规文档。</li><li>Table: 专门处理复杂表格。</li></ul></li><li><ol start="4"><li>开始解析: 点击 &quot;Parse&quot;，等待状态变为 &quot;Success&quot;。</li></ol></li></ul><h2 id="五、-实现-ai-对话-chat" tabindex="-1">五、 实现 AI 对话 (Chat) <a class="header-anchor" href="#五、-实现-ai-对话-chat" aria-hidden="true">#</a></h2><ul><li><ol><li>进入 &quot;Chat&quot; 页面，新建一个聊天窗口。</li></ol></li><li><ol start="2"><li>挂载知识库: 在右侧设置面板的 Knowledge Bases 中勾选刚才创建的库。</li></ol></li><li><ol start="3"><li>开始对话: 询问文档内容，系统会基于检索到的片段回答，并标注 Citations (来源引用)。</li></ol></li></ul><h2 id="六、-踩坑避雷针-troubleshooting-⚡" tabindex="-1">六、 踩坑避雷针 (Troubleshooting) ⚡ <a class="header-anchor" href="#六、-踩坑避雷针-troubleshooting-⚡" aria-hidden="true">#</a></h2><table><thead><tr><th>报错/问题</th><th>常见原因</th><th>解决方案</th></tr></thead><tbody><tr><td>80 端口被占用</td><td>本地有 Nginx 或 IIS 服务</td><td>编辑 <code>docker-compose.yml</code>，将 <code>- 80:80</code> 改为 <code>- 8080:80</code></td></tr><tr><td>解析一直 Pending</td><td>未配置 Embedding 模型</td><td>在用户设置里检查是否选择了默认的向量模型</td></tr><tr><td>Docker 容器闪退</td><td>宿主机内存不足 (OOM)</td><td>增加系统虚拟内存，或在 Docker 设置中调高内存限额至 16G。</td></tr><tr><td>无法连接本地 Ollama</td><td>Docker 网络隔离</td><td>不要写 <code>127.0.0.1</code>，必须写 <code>http://host.docker.internal:11434</code></td></tr><tr><td>PDF 解析不准</td><td>文档布局过于复杂</td><td>在解析设置中尝试更换 <strong>Layout Analysis</strong> 模板。</td></tr></tbody></table><h2 id="七、-维护建议" tabindex="-1">七、 维护建议 <a class="header-anchor" href="#七、-维护建议" aria-hidden="true">#</a></h2><ul><li><ol><li>更新版本: git pull 后重新执行 docker compose up -d。</li></ol></li><li><ol start="2"><li>清理缓存: 定期检查 Docker 占用的磁盘空间，使用 docker system prune（慎用）。</li></ol></li></ul>`,41),n=[i];function o(r,d,c,h,p,u){return e(),a("div",null,n)}const y=l(s,[["render",o]]);export{_ as __pageData,y as default};
